// Filter contacts approaching Medicare eligibility (turning 65 in next 60 days)
// Also identify existing Medicare clients during AEP

const today = new Date();
const contacts = $input.all();

const eligibleContacts = [];

for (const contactWrapper of contacts) {
  const contact = contactWrapper.json;

  // Skip if no birthday field
  const birthdayField = contact.customFields?.find(f => f.key === 'birthday' || f.key === 'date_of_birth');
  if (!birthdayField) continue;

  const birthDate = new Date(birthdayField.value);
  if (isNaN(birthDate.getTime())) continue;

  // Calculate age at end of current year
  const turning65Date = new Date(today.getFullYear(), birthDate.getMonth(), birthDate.getDate());
  const ageThisYear = today.getFullYear() - birthDate.getFullYear();

  // Check if turning 65 within next 60 days or in current year
  const sixtyDaysFromNow = new Date(today.getTime() + (60 * 24 * 60 * 60 * 1000));

  if (turning65Date >= today && turning65Date <= sixtyDaysFromNow) {
    eligibleContacts.push({
      ...contact,
      turning65Date: turning65Date.toISOString(),
      monthsUntil65: Math.ceil((turning65Date - today) / (30 * 24 * 60 * 60 * 1000)),
      segment: 'Turning 65 Soon'
    });
  } else if (ageThisYear >= 65) {
    // Already on Medicare - check if they need review
    const tags = contact.tags || [];
    if (!tags.includes('Medicare Client') && !tags.includes('AEP Contacted')) {
      eligibleContacts.push({
        ...contact,
        ageThisYear,
        segment: 'Medicare Client Review'
      });
    }
  }
}

return eligibleContacts.slice(0, 50); // Process max 50 at a time

